import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './Suppliers.css';

function Suppliers() {
  const [suppliers, setSuppliers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchSuppliers = async () => {
      try {
        const res = await axios.get('/api/suppliers');
        setSuppliers(res.data);
      } catch (err) {
        console.error('Error loading suppliers', err);
      } finally {
        setLoading(false);
      }
    };
    fetchSuppliers();
  }, []);

  return (
    <div className="suppliers-page">
      <div className="container">
        <div className="suppliers-header">
          <h1>Suppliers Directory</h1>
          <p>Discover verified suppliers and manufacturers</p>
        </div>

        {loading ? (
          <div className="loading">Loading suppliers...</div>
        ) : (
          <div className="suppliers-grid">
            {suppliers.map((supplier) => (
              <Link
                key={supplier.id}
                to={`/suppliers/${supplier.id}`}
                className="supplier-card"
              >
                <div className="supplier-avatar">
                  {supplier.name?.charAt(0)}
                </div>
                <div className="supplier-info">
                  <h3>{supplier.name}</h3>
                  <p className="supplier-location">{supplier.location}</p>
                  <p className="supplier-description">
                    {supplier.description?.slice(0, 120)}...
                  </p>
                  <p className="supplier-count">{supplier.product_count} products</p>
                </div>
              </Link>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default Suppliers;
